   511→/* Curl_init_CONNECT() gets called each time the handle switches to CONNECT
   512→   which means this gets called once for each subsequent redirect etc */
   513→void Curl_init_CONNECT(struct Curl_easy *data)
   514→{
   515→  data->state.fread_func = data->set.fread_func_set;
   516→  data->state.in = data->set.in_set;
   517→  data->state.upload = (data->state.httpreq == HTTPREQ_PUT);
   518→}
   519→
   520→/*
   521→ * Curl_pretransfer() is called immediately before a transfer starts, and only
   522→ * once for one transfer no matter if it has redirects or do multi-pass
   523→ * authentication etc.
   524→ */
   525→CURLcode Curl_pretransfer(struct Curl_easy *data)
   526→{
   527→  CURLcode result = CURLE_OK;
   528→
   529→  if(!data->set.str[STRING_SET_URL] && !data->set.uh) {
   530→    /* we cannot do anything without URL */
   531→    failf(data, "No URL set");
   532→    return CURLE_URL_MALFORMAT;
   533→  }
   534→
   535→  /* CURLOPT_CURLU overrides CURLOPT_URL and the contents of the CURLU handle
   536→     is allowed to be changed by the user between transfers */
   537→  if(data->set.uh) {
   538→    CURLUcode uc;
   539→    free(data->set.str[STRING_SET_URL]);
   540→    uc = curl_url_get(data->set.uh,
   541→                      CURLUPART_URL, &data->set.str[STRING_SET_URL], 0);
   542→    if(uc) {
   543→      failf(data, "No URL set");
   544→      return CURLE_URL_MALFORMAT;
   545→    }
   546→  }
   547→
   548→  /* since the URL may have been redirected in a previous use of this handle */
   549→  if(data->state.url_alloc) {
   550→    Curl_safefree(data->state.url);
   551→    data->state.url_alloc = FALSE;
   552→  }
   553→
   554→  data->state.url = data->set.str[STRING_SET_URL];
   555→
   556→  if(data->set.postfields && data->set.set_resume_from) {
   557→    /* we cannot */
   558→    failf(data, "cannot mix POSTFIELDS with RESUME_FROM");
   559→    return CURLE_BAD_FUNCTION_ARGUMENT;
   560→  }
   561→
   562→  data->state.prefer_ascii = data->set.prefer_ascii;
   563→#ifdef CURL_LIST_ONLY_PROTOCOL
   564→  data->state.list_only = data->set.list_only;
   565→#endif
   566→  data->state.httpreq = data->set.method;
   567→
   568→#ifdef USE_SSL
   569→  if(!data->state.ssl_scache)
   570→    /* There was no ssl session cache set via a share, use the multi one */
   571→    data->state.ssl_scache = data->multi->ssl_scache;
   572→#endif
   573→
   574→  data->state.requests = 0;
   575→  data->state.followlocation = 0; /* reset the location-follow counter */
   576→  data->state.this_is_a_follow = FALSE; /* reset this */
   577→  data->state.errorbuf = FALSE; /* no error has occurred */
   578→  data->state.httpwant = data->set.httpwant;
   579→  data->state.httpversion = 0;
   580→  data->state.authproblem = FALSE;
   581→  data->state.authhost.want = data->set.httpauth;
   582→  data->state.authproxy.want = data->set.proxyauth;
   583→  Curl_safefree(data->info.wouldredirect);
   584→  Curl_data_priority_clear_state(data);
   585→
   586→  if(data->state.httpreq == HTTPREQ_PUT)
   587→    data->state.infilesize = data->set.filesize;
   588→  else if((data->state.httpreq != HTTPREQ_GET) &&
   589→          (data->state.httpreq != HTTPREQ_HEAD)) {
   590→    data->state.infilesize = data->set.postfieldsize;
   591→    if(data->set.postfields && (data->state.infilesize == -1))
   592→      data->state.infilesize = (curl_off_t)strlen(data->set.postfields);
   593→  }
   594→  else
   595→    data->state.infilesize = 0;
   596→
   597→  /* If there is a list of cookie files to read, do it now! */
   598→  Curl_cookie_loadfiles(data);
   599→
   600→  /* If there is a list of host pairs to deal with */
   601→  if(data->state.resolve)
   602→    result = Curl_loadhostpairs(data);
   603→
   604→  /* If there is a list of hsts files to read */
   605→  Curl_hsts_loadfiles(data);
   606→
   607→  if(!result) {
   608→    /* Allow data->set.use_port to set which port to use. This needs to be
   609→     * disabled for example when we follow Location: headers to URLs using
   610→     * different ports! */
   611→    data->state.allow_port = TRUE;
   612→
   613→#if defined(HAVE_SIGNAL) && defined(SIGPIPE) && !defined(HAVE_MSG_NOSIGNAL)
   614→    /*************************************************************
   615→     * Tell signal handler to ignore SIGPIPE
   616→     *************************************************************/
   617→    if(!data->set.no_signal)
   618→      data->state.prev_signal = signal(SIGPIPE, SIG_IGN);
   619→#endif
   620→
   621→    Curl_initinfo(data); /* reset session-specific information "variables" */
   622→    Curl_pgrsResetTransferSizes(data);
   623→    Curl_pgrsStartNow(data);
   624→
   625→    /* In case the handle is reused and an authentication method was picked
   626→       in the session we need to make sure we only use the one(s) we now
   627→       consider to be fine */
   628→    data->state.authhost.picked &= data->state.authhost.want;
   629→    data->state.authproxy.picked &= data->state.authproxy.want;
   630→
   631→#ifndef CURL_DISABLE_FTP
   632→    data->state.wildcardmatch = data->set.wildcard_enabled;
   633→    if(data->state.wildcardmatch) {
   634→      struct WildcardData *wc;
   635→      if(!data->wildcard) {
   636→        data->wildcard = calloc(1, sizeof(struct WildcardData));
   637→        if(!data->wildcard)
   638→          return CURLE_OUT_OF_MEMORY;
   639→      }
   640→      wc = data->wildcard;
   641→      if(wc->state < CURLWC_INIT) {
   642→        if(wc->ftpwc)
   643→          wc->dtor(wc->ftpwc);
   644→        Curl_safefree(wc->pattern);
   645→        Curl_safefree(wc->path);
   646→        result = Curl_wildcard_init(wc); /* init wildcard structures */
   647→        if(result)
   648→          return CURLE_OUT_OF_MEMORY;
   649→      }
   650→    }
   651→#endif
   652→    result = Curl_hsts_loadcb(data, data->hsts);
   653→  }
   654→
   655→  /*
   656→   * Set user-agent. Used for HTTP, but since we can attempt to tunnel
   657→   * basically anything through an HTTP proxy we cannot limit this based on
   658→   * protocol.
   659→   */
   660→  if(data->set.str[STRING_USERAGENT]) {
   661→    Curl_safefree(data->state.aptr.uagent);
   662→    data->state.aptr.uagent =
   663→      aprintf("User-Agent: %s\r\n", data->set.str[STRING_USERAGENT]);
   664→    if(!data->state.aptr.uagent)
   665→      return CURLE_OUT_OF_MEMORY;
   666→  }
   667→
   668→  if(data->set.str[STRING_USERNAME] ||
   669→     data->set.str[STRING_PASSWORD])
   670→    data->state.creds_from = CREDS_OPTION;
   671→  if(!result)
   672→    result = Curl_setstropt(&data->state.aptr.user,
   673→                            data->set.str[STRING_USERNAME]);
   674→  if(!result)
   675→    result = Curl_setstropt(&data->state.aptr.passwd,
   676→                            data->set.str[STRING_PASSWORD]);
   677→#ifndef CURL_DISABLE_PROXY
   678→  if(!result)
   679→    result = Curl_setstropt(&data->state.aptr.proxyuser,
   680→                            data->set.str[STRING_PROXYUSERNAME]);
   681→  if(!result)
   682→    result = Curl_setstropt(&data->state.aptr.proxypasswd,
   683→                            data->set.str[STRING_PROXYPASSWORD]);
   684→#endif
   685→
   686→  data->req.headerbytecount = 0;
   687→  Curl_headers_cleanup(data);
   688→  return result;
   689→}
