   691→/* Returns CURLE_OK *and* sets '*url' if a request retry is wanted.
   692→
   693→   NOTE: that the *url is malloc()ed. */
   694→CURLcode Curl_retry_request(struct Curl_easy *data, char **url)
   695→{
   696→  struct connectdata *conn = data->conn;
   697→  bool retry = FALSE;
   698→  *url = NULL;
   699→
   700→  /* if we are talking upload, we cannot do the checks below, unless the
   701→     protocol is HTTP as when uploading over HTTP we will still get a
   702→     response */
   703→  if(data->state.upload &&
   704→     !(conn->handler->protocol&(PROTO_FAMILY_HTTP|CURLPROTO_RTSP)))
   705→    return CURLE_OK;
   706→
   707→  if((data->req.bytecount + data->req.headerbytecount == 0) &&
   708→     conn->bits.reuse &&
   709→     (!data->req.no_body || (conn->handler->protocol & PROTO_FAMILY_HTTP))
   710→#ifndef CURL_DISABLE_RTSP
   711→     && (data->set.rtspreq != RTSPREQ_RECEIVE)
   712→#endif
   713→    )
   714→    /* We got no data, we attempted to reuse a connection. For HTTP this
   715→       can be a retry so we try again regardless if we expected a body.
   716→       For other protocols we only try again only if we expected a body.
   717→
   718→       This might happen if the connection was left alive when we were
   719→       done using it before, but that was closed when we wanted to read from
   720→       it again. Bad luck. Retry the same request on a fresh connect! */
   721→    retry = TRUE;
   722→  else if(data->state.refused_stream &&
   723→          (data->req.bytecount + data->req.headerbytecount == 0) ) {
   724→    /* This was sent on a refused stream, safe to rerun. A refused stream
   725→       error can typically only happen on HTTP/2 level if the stream is safe
   726→       to issue again, but the nghttp2 API can deliver the message to other
   727→       streams as well, which is why this adds the check the data counters
   728→       too. */
   729→    infof(data, "REFUSED_STREAM, retrying a fresh connect");
   730→    data->state.refused_stream = FALSE; /* clear again */
   731→    retry = TRUE;
   732→  }
   733→  if(retry) {
   734→#define CONN_MAX_RETRIES 5
   735→    if(data->state.retrycount++ >= CONN_MAX_RETRIES) {
   736→      failf(data, "Connection died, tried %d times before giving up",
   737→            CONN_MAX_RETRIES);
   738→      data->state.retrycount = 0;
   739→      return CURLE_SEND_ERROR;
   740→    }
   741→    infof(data, "Connection died, retrying a fresh connect (retry count: %d)",
   742→          data->state.retrycount);
   743→    *url = strdup(data->state.url);
   744→    if(!*url)
   745→      return CURLE_OUT_OF_MEMORY;
   746→
   747→    connclose(conn, "retry"); /* close this connection */
   748→    conn->bits.retry = TRUE; /* mark this as a connection we are about
   749→                                to retry. Marking it this way should
   750→                                prevent i.e HTTP transfers to return
   751→                                error just because nothing has been
   752→                                transferred! */
   753→    Curl_creader_set_rewind(data, TRUE);
   754→  }
   755→  return CURLE_OK;
   756→}
   757→
   758→/*
   759→ * xfer_setup() is called to setup basic properties for the transfer.
   760→ */
   761→static void xfer_setup(
   762→  struct Curl_easy *data,   /* transfer */
   763→  int sockindex,            /* socket index to read from or -1 */
   764→  curl_off_t size,          /* -1 if unknown at this point */
   765→  bool getheader,           /* TRUE if header parsing is wanted */
   766→  int writesockindex,       /* socket index to write to, it may be the same we
   767→                               read from. -1 disables */
   768→  bool shutdown,            /* shutdown connection at transfer end. Only
   769→                             * supported when sending OR receiving. */
   770→  bool shutdown_err_ignore  /* errors during shutdown do not fail the
   771→                             * transfer */
   772→  )
   773→{
   774→  struct SingleRequest *k = &data->req;
   775→  struct connectdata *conn = data->conn;
   776→  bool want_send = Curl_req_want_send(data);
   777→
   778→  DEBUGASSERT(conn != NULL);
   779→  DEBUGASSERT((sockindex <= 1) && (sockindex >= -1));
   780→  DEBUGASSERT((writesockindex <= 1) && (writesockindex >= -1));
   781→  DEBUGASSERT(!shutdown || (sockindex == -1) || (writesockindex == -1));
   782→
   783→  if(Curl_conn_is_multiplex(conn, FIRSTSOCKET) || want_send) {
   784→    /* when multiplexing, the read/write sockets need to be the same! */
   785→    conn->sockfd = sockindex == -1 ?
   786→      ((writesockindex == -1 ? CURL_SOCKET_BAD : conn->sock[writesockindex])) :
   787→      conn->sock[sockindex];
   788→    conn->writesockfd = conn->sockfd;
   789→    if(want_send)
   790→      /* special and HTTP-specific */
   791→      writesockindex = FIRSTSOCKET;
   792→  }
   793→  else {
   794→    conn->sockfd = sockindex == -1 ?
   795→      CURL_SOCKET_BAD : conn->sock[sockindex];
   796→    conn->writesockfd = writesockindex == -1 ?
   797→      CURL_SOCKET_BAD : conn->sock[writesockindex];
   798→  }
   799→
   800→  k->getheader = getheader;
   801→  k->size = size;
   802→  k->shutdown = shutdown;
   803→  k->shutdown_err_ignore = shutdown_err_ignore;
   804→
   805→  /* The code sequence below is placed in this function just because all
   806→     necessary input is not always known in do_complete() as this function may
   807→     be called after that */
   808→
   809→  if(!k->getheader) {
   810→    k->header = FALSE;
   811→    if(size > 0)
   812→      Curl_pgrsSetDownloadSize(data, size);
   813→  }
   814→  /* we want header and/or body, if neither then do not do this! */
   815→  if(k->getheader || !data->req.no_body) {
   816→
   817→    if(sockindex != -1)
   818→      k->keepon |= KEEP_RECV;
   819→
   820→    if(writesockindex != -1)
   821→      k->keepon |= KEEP_SEND;
   822→  } /* if(k->getheader || !data->req.no_body) */
   823→
   824→}
   825→
   826→void Curl_xfer_setup_nop(struct Curl_easy *data)
   827→{
   828→  xfer_setup(data, -1, -1, FALSE, -1, FALSE, FALSE);
   829→}
   830→
   831→void Curl_xfer_setup1(struct Curl_easy *data,
   832→                      int send_recv,
   833→                      curl_off_t recv_size,
   834→                      bool getheader)
   835→{
   836→  int recv_index = (send_recv & CURL_XFER_RECV) ? FIRSTSOCKET : -1;
   837→  int send_index = (send_recv & CURL_XFER_SEND) ? FIRSTSOCKET : -1;
   838→  DEBUGASSERT((recv_index >= 0) || (recv_size == -1));
   839→  xfer_setup(data, recv_index, recv_size, getheader, send_index, FALSE, FALSE);
   840→}
   841→
   842→void Curl_xfer_setup2(struct Curl_easy *data,
   843→                      int send_recv,
   844→                      curl_off_t recv_size,
   845→                      bool shutdown,
   846→                      bool shutdown_err_ignore)
   847→{
   848→  int recv_index = (send_recv & CURL_XFER_RECV) ? SECONDARYSOCKET : -1;
   849→  int send_index = (send_recv & CURL_XFER_SEND) ? SECONDARYSOCKET : -1;
   850→  DEBUGASSERT((recv_index >= 0) || (recv_size == -1));
   851→  xfer_setup(data, recv_index, recv_size, FALSE, send_index,
   852→             shutdown, shutdown_err_ignore);
   853→}
   854→
   855→CURLcode Curl_xfer_write_resp(struct Curl_easy *data,
   856→                              const char *buf, size_t blen,
   857→                              bool is_eos)
   858→{
   859→  CURLcode result = CURLE_OK;
   860→
   861→  if(data->conn->handler->write_resp) {
   862→    /* protocol handlers offering this function take full responsibility
   863→     * for writing all received download data to the client. */
   864→    result = data->conn->handler->write_resp(data, buf, blen, is_eos);
   865→  }
   866→  else {
   867→    /* No special handling by protocol handler, write all received data
   868→     * as BODY to the client. */
   869→    if(blen || is_eos) {
   870→      int cwtype = CLIENTWRITE_BODY;
   871→      if(is_eos)
   872→        cwtype |= CLIENTWRITE_EOS;
   873→      result = Curl_client_write(data, cwtype, buf, blen);
   874→    }
   875→  }
   876→
   877→  if(!result && is_eos) {
   878→    /* If we wrote the EOS, we are definitely done */
   879→    data->req.eos_written = TRUE;
   880→    data->req.download_done = TRUE;
   881→  }
   882→  CURL_TRC_WRITE(data, "xfer_write_resp(len=%zu, eos=%d) -> %d",
   883→                 blen, is_eos, result);
   884→  return result;
   885→}
   886→
   887→CURLcode Curl_xfer_write_resp_hd(struct Curl_easy *data,
   888→                                 const char *hd0, size_t hdlen, bool is_eos)
   889→{
   890→  if(data->conn->handler->write_resp_hd) {
   891→    /* protocol handlers offering this function take full responsibility
   892→     * for writing all received download data to the client. */
   893→    return data->conn->handler->write_resp_hd(data, hd0, hdlen, is_eos);
   894→  }
   895→  /* No special handling by protocol handler, write as response bytes */
   896→  return Curl_xfer_write_resp(data, hd0, hdlen, is_eos);
   897→}
   898→
   899→CURLcode Curl_xfer_write_done(struct Curl_easy *data, bool premature)
   900→{
   901→  (void)premature;
   902→  return Curl_cw_out_done(data);
   903→}
   904→
   905→bool Curl_xfer_needs_flush(struct Curl_easy *data)
   906→{
   907→  int sockindex;
   908→  sockindex = ((data->conn->writesockfd != CURL_SOCKET_BAD) &&
   909→               (data->conn->writesockfd == data->conn->sock[SECONDARYSOCKET]));
   910→  return Curl_conn_needs_flush(data, sockindex);
   911→}
   912→
   913→CURLcode Curl_xfer_flush(struct Curl_easy *data)
   914→{
   915→  int sockindex;
   916→  sockindex = ((data->conn->writesockfd != CURL_SOCKET_BAD) &&
   917→               (data->conn->writesockfd == data->conn->sock[SECONDARYSOCKET]));
   918→  return Curl_conn_flush(data, sockindex);
   919→}
   920→
   921→CURLcode Curl_xfer_send(struct Curl_easy *data,
   922→                        const void *buf, size_t blen, bool eos,
   923→                        size_t *pnwritten)
   924→{
   925→  CURLcode result;
   926→  int sockindex;
   927→
   928→  DEBUGASSERT(data);
   929→  DEBUGASSERT(data->conn);
   930→
   931→  sockindex = ((data->conn->writesockfd != CURL_SOCKET_BAD) &&
   932→               (data->conn->writesockfd == data->conn->sock[SECONDARYSOCKET]));
   933→  result = Curl_conn_send(data, sockindex, buf, blen, eos, pnwritten);
   934→  if(result == CURLE_AGAIN) {
   935→    result = CURLE_OK;
   936→    *pnwritten = 0;
   937→  }
   938→  else if(!result && *pnwritten)
   939→    data->info.request_size += *pnwritten;
   940→
   941→  DEBUGF(infof(data, "Curl_xfer_send(len=%zu, eos=%d) -> %d, %zu",
   942→               blen, eos, result, *pnwritten));
   943→  return result;
   944→}
   945→
   946→CURLcode Curl_xfer_recv(struct Curl_easy *data,
   947→                        char *buf, size_t blen,
   948→                        ssize_t *pnrcvd)
   949→{
   950→  int sockindex;
   951→
   952→  DEBUGASSERT(data);
   953→  DEBUGASSERT(data->conn);
   954→  DEBUGASSERT(data->set.buffer_size > 0);
   955→
   956→  sockindex = ((data->conn->sockfd != CURL_SOCKET_BAD) &&
   957→               (data->conn->sockfd == data->conn->sock[SECONDARYSOCKET]));
   958→  if((size_t)data->set.buffer_size < blen)
   959→    blen = (size_t)data->set.buffer_size;
   960→  return Curl_conn_recv(data, sockindex, buf, blen, pnrcvd);
   961→}
   962→
   963→CURLcode Curl_xfer_send_close(struct Curl_easy *data)
   964→{
   965→  Curl_conn_ev_data_done_send(data);
   966→  return CURLE_OK;
   967→}
   968→
   969→bool Curl_xfer_is_blocked(struct Curl_easy *data)
   970→{
   971→  bool want_send = ((data)->req.keepon & KEEP_SEND);
   972→  bool want_recv = ((data)->req.keepon & KEEP_RECV);
   973→  if(!want_send)
   974→    return want_recv && Curl_cwriter_is_paused(data);
   975→  else if(!want_recv)
   976→    return want_send && Curl_creader_is_paused(data);
   977→  else
   978→    return Curl_creader_is_paused(data) && Curl_cwriter_is_paused(data);
   979→}
