   125→     its internal buffers so we MUST always try until we get EAGAIN back */
   126→  return conn->handler->protocol&(CURLPROTO_SCP|CURLPROTO_SFTP) ||
   127→    Curl_conn_data_pending(data, FIRSTSOCKET);
   128→}
