   162→static CURLcode xfer_recv_shutdown(struct Curl_easy *data, bool *done)
   163→{
   164→  int sockindex;
   165→
   166→  if(data->conn->sockfd == CURL_SOCKET_BAD)
   167→    return CURLE_FAILED_INIT;
   168→  sockindex = (data->conn->sockfd == data->conn->sock[SECONDARYSOCKET]);
   169→  return Curl_conn_shutdown(data, sockindex, done);
