   196→/**
   197→ * Receive raw response data for the transfer.
   198→ * @param data         the transfer
   199→ * @param buf          buffer to keep response data received
   200→ * @param blen         length of `buf`
   201→ * @param eos_reliable if EOS detection in underlying connection is reliable
   202→ * @param err error    code in case of -1 return
   203→ * @return number of bytes read or -1 for error
   204→ */
   205→static ssize_t xfer_recv_resp(struct Curl_easy *data,
   206→                              char *buf, size_t blen,
   207→                              bool eos_reliable,
   208→                              CURLcode *err)
   209→{
   210→  ssize_t nread;
   211→
   212→  DEBUGASSERT(blen > 0);
   213→  /* If we are reading BODY data and the connection does NOT handle EOF
   214→   * and we know the size of the BODY data, limit the read amount */
   215→  if(!eos_reliable && !data->req.header && data->req.size != -1) {
   216→    curl_off_t totalleft = data->req.size - data->req.bytecount;
   217→    if(totalleft <= 0)
   218→      blen = 0;
   219→    else if(totalleft < (curl_off_t)blen)
   220→      blen = (size_t)totalleft;
   221→  }
   222→  else if(xfer_recv_shutdown_started(data)) {
   223→    /* we already received everything. Do not try more. */
   224→    blen = 0;
   225→  }
   226→
   227→  if(!blen) {
   228→    /* want nothing more */
   229→    *err = CURLE_OK;
   230→    nread = 0;
   231→  }
   232→  else {
   233→    *err = Curl_xfer_recv(data, buf, blen, &nread);
   234→  }
   235→
   236→  if(*err)
   237→    return -1;
   238→  if(nread == 0) {
   239→    if(data->req.shutdown) {
   240→      bool done;
   241→      *err = xfer_recv_shutdown(data, &done);
   242→      if(*err)
   243→        return -1;
   244→      if(!done) {
   245→        *err = CURLE_AGAIN;
   246→        return -1;
   247→      }
   248→    }
   249→    DEBUGF(infof(data, "sendrecv_dl: we are done"));
   250→  }
   251→  DEBUGASSERT(nread >= 0);
   252→  return nread;
   253→}
   254→
   255→/*
   256→ * Go ahead and do a read if we have a readable socket or if
   257→ * the stream was rewound (in which case we have data in a
   258→ * buffer)
   259→ */
   260→static CURLcode sendrecv_dl(struct Curl_easy *data,
   261→                            struct SingleRequest *k,
   262→                            int *didwhat)
   263→{
   264→  struct connectdata *conn = data->conn;
   265→  CURLcode result = CURLE_OK;
   266→  char *buf, *xfer_buf;
   267→  size_t blen, xfer_blen;
   268→  int maxloops = 10;
   269→  curl_off_t total_received = 0;
   270→  bool is_multiplex = FALSE;
   271→
   272→  result = Curl_multi_xfer_buf_borrow(data, &xfer_buf, &xfer_blen);
   273→  if(result)
   274→    goto out;
   275→
   276→  /* This is where we loop until we have read everything there is to
   277→     read or we get a CURLE_AGAIN */
   278→  do {
   279→    bool is_eos = FALSE;
   280→    size_t bytestoread;
   281→    ssize_t nread;
   282→
   283→    if(!is_multiplex) {
   284→      /* Multiplexed connection have inherent handling of EOF and we do not
   285→       * have to carefully restrict the amount we try to read.
   286→       * Multiplexed changes only in one direction. */
   287→      is_multiplex = Curl_conn_is_multiplex(conn, FIRSTSOCKET);
   288→    }
   289→
   290→    buf = xfer_buf;
   291→    bytestoread = xfer_blen;
   292→
   293→    if(bytestoread && data->set.max_recv_speed > 0) {
   294→      /* In case of speed limit on receiving: if this loop already got
   295→       * data, break out. If not, limit the amount of bytes to receive.
   296→       * The overall, timed, speed limiting is done in multi.c */
   297→      if(total_received)
   298→        break;
   299→      if(data->set.max_recv_speed < (curl_off_t)bytestoread)
   300→        bytestoread = (size_t)data->set.max_recv_speed;
   301→    }
   302→
   303→    nread = xfer_recv_resp(data, buf, bytestoread, is_multiplex, &result);
   304→    if(nread < 0) {
   305→      if(CURLE_AGAIN != result)
   306→        goto out; /* real error */
   307→      result = CURLE_OK;
   308→      if(data->req.download_done && data->req.no_body &&
   309→         !data->req.resp_trailer) {
   310→        DEBUGF(infof(data, "EAGAIN, download done, no trailer announced, "
   311→               "not waiting for EOS"));
   312→        nread = 0;
   313→        /* continue as if we read the EOS */
   314→      }
   315→      else
   316→        break; /* get out of loop */
   317→    }
   318→
   319→    /* We only get a 0-length read on EndOfStream */
   320→    blen = (size_t)nread;
   321→    is_eos = (blen == 0);
   322→    *didwhat |= KEEP_RECV;
   323→
   324→    if(!blen) {
   325→      /* if we receive 0 or less here, either the data transfer is done or the
   326→         server closed the connection and we bail out from this! */
   327→      if(is_multiplex)
   328→        DEBUGF(infof(data, "nread == 0, stream closed, bailing"));
   329→      else
   330→        DEBUGF(infof(data, "nread <= 0, server closed connection, bailing"));
   331→      result = Curl_req_stop_send_recv(data);
   332→      if(result)
   333→        goto out;
   334→      if(k->eos_written) /* already did write this to client, leave */
   335→        break;
   336→    }
   337→    total_received += blen;
   338→
   339→    result = Curl_xfer_write_resp(data, buf, blen, is_eos);
   340→    if(result || data->req.done)
   341→      goto out;
   342→
   343→    /* if we are done, we stop receiving. On multiplexed connections,
   344→     * we should read the EOS. Which may arrive as meta data after
   345→     * the bytes. Not taking it in might lead to RST of streams. */
   346→    if((!is_multiplex && data->req.download_done) || is_eos) {
   347→      data->req.keepon &= ~KEEP_RECV;
   348→    }
   349→    /* if we are PAUSEd or stopped receiving, leave the loop */
   350→    if((k->keepon & KEEP_RECV_PAUSE) || !(k->keepon & KEEP_RECV))
   351→      break;
   352→
   353→  } while(maxloops--);
   354→
   355→  if((maxloops <= 0) || data_pending(data)) {
   356→    /* did not read until EAGAIN or there is still pending data, mark as
   357→       read-again-please */
   358→    data->state.select_bits = CURL_CSELECT_IN;
   359→    if((k->keepon & KEEP_SENDBITS) == KEEP_SEND)
   360→      data->state.select_bits |= CURL_CSELECT_OUT;
   361→  }
   362→
   363→  if(((k->keepon & (KEEP_RECV|KEEP_SEND)) == KEEP_SEND) &&
   364→     (conn->bits.close || is_multiplex)) {
   365→    /* When we have read the entire thing and the close bit is set, the server
   366→       may now close the connection. If there is now any kind of sending going
   367→       on from our side, we need to stop that immediately. */
   368→    infof(data, "we are done reading and this is set to close, stop send");
   369→    Curl_req_abort_sending(data);
   370→  }
   371→
   372→out:
   373→  Curl_multi_xfer_buf_release(data, xfer_buf);
   374→  if(result)
   375→    DEBUGF(infof(data, "sendrecv_dl() -> %d", result));
   376→  return result;
   377→}
