   855→CURLcode Curl_xfer_write_resp(struct Curl_easy *data,
   856→                              const char *buf, size_t blen,
   857→                              bool is_eos)
   858→{
   859→  CURLcode result = CURLE_OK;
   860→
   861→  if(data->conn->handler->write_resp) {
   862→    /* protocol handlers offering this function take full responsibility
   863→     * for writing all received download data to the client. */
   864→    result = data->conn->handler->write_resp(data, buf, blen, is_eos);
   865→  }
   866→  else {
   867→    /* No special handling by protocol handler, write all received data
   868→     * as BODY to the client. */
   869→    if(blen || is_eos) {
   870→      int cwtype = CLIENTWRITE_BODY;
   871→      if(is_eos)
   872→        cwtype |= CLIENTWRITE_EOS;
   873→      result = Curl_client_write(data, cwtype, buf, blen);
   874→    }
   875→  }
   876→
   877→  if(!result && is_eos) {
   878→    /* If we wrote the EOS, we are definitely done */
   879→    data->req.eos_written = TRUE;
   880→    data->req.download_done = TRUE;
   881→  }
   882→  CURL_TRC_WRITE(data, "xfer_write_resp(len=%zu, eos=%d) -> %d",
   883→                 blen, is_eos, result);
   884→  return result;
   885→}
   886→
   887→CURLcode Curl_xfer_write_resp_hd(struct Curl_easy *data,
   888→                                 const char *hd0, size_t hdlen, bool is_eos)
   889→{
   890→  if(data->conn->handler->write_resp_hd) {
   891→    /* protocol handlers offering this function take full responsibility
   892→     * for writing all received download data to the client. */
   893→    return data->conn->handler->write_resp_hd(data, hd0, hdlen, is_eos);
   894→  }
   895→  /* No special handling by protocol handler, write as response bytes */
   896→  return Curl_xfer_write_resp(data, hd0, hdlen, is_eos);
   897→}
   898→
   899→CURLcode Curl_xfer_write_done(struct Curl_easy *data, bool premature)
   900→{
   901→  (void)premature;
   902→  return Curl_cw_out_done(data);
   903→}
