   905→bool Curl_xfer_needs_flush(struct Curl_easy *data)
   906→{
   907→  int sockindex;
   908→  sockindex = ((data->conn->writesockfd != CURL_SOCKET_BAD) &&
   909→               (data->conn->writesockfd == data->conn->sock[SECONDARYSOCKET]));
   910→  return Curl_conn_needs_flush(data, sockindex);
   911→}
