   913→CURLcode Curl_xfer_flush(struct Curl_easy *data)
   914→{
   915→  int sockindex;
   916→  sockindex = ((data->conn->writesockfd != CURL_SOCKET_BAD) &&
   917→               (data->conn->writesockfd == data->conn->sock[SECONDARYSOCKET]));
   918→  return Curl_conn_flush(data, sockindex);
   919→}
