   921→CURLcode Curl_xfer_send(struct Curl_easy *data,
   922→                        const void *buf, size_t blen, bool eos,
   923→                        size_t *pnwritten)
   924→{
   925→  CURLcode result;
   926→  int sockindex;
   927→
   928→  DEBUGASSERT(data);
   929→  DEBUGASSERT(data->conn);
   930→
   931→  sockindex = ((data->conn->writesockfd != CURL_SOCKET_BAD) &&
   932→               (data->conn->writesockfd == data->conn->sock[SECONDARYSOCKET]));
   933→  result = Curl_conn_send(data, sockindex, buf, blen, eos, pnwritten);
   934→  if(result == CURLE_AGAIN) {
   935→    result = CURLE_OK;
   936→    *pnwritten = 0;
   937→  }
   938→  else if(!result && *pnwritten)
   939→    data->info.request_size += *pnwritten;
   940→
   941→  DEBUGF(infof(data, "Curl_xfer_send(len=%zu, eos=%d) -> %d, %zu",
   942→               blen, eos, result, *pnwritten));
   943→  return result;
   944→}
   945→
   946→CURLcode Curl_xfer_recv(struct Curl_easy *data,
   947→                        char *buf, size_t blen,
   948→                        ssize_t *pnrcvd)
   949→{
   950→  int sockindex;
   951→
   952→  DEBUGASSERT(data);
   953→  DEBUGASSERT(data->conn);
   954→  DEBUGASSERT(data->set.buffer_size > 0);
   955→
   956→  sockindex = ((data->conn->sockfd != CURL_SOCKET_BAD) &&
   957→               (data->conn->sockfd == data->conn->sock[SECONDARYSOCKET]));
   958→  if((size_t)data->set.buffer_size < blen)
   959→    blen = (size_t)data->set.buffer_size;
   960→  return Curl_conn_recv(data, sockindex, buf, blen, pnrcvd);
   961→}
