   969→bool Curl_xfer_is_blocked(struct Curl_easy *data)
   970→{
   971→  bool want_send = ((data)->req.keepon & KEEP_SEND);
   972→  bool want_recv = ((data)->req.keepon & KEEP_RECV);
   973→  if(!want_send)
   974→    return want_recv && Curl_cwriter_is_paused(data);
   975→  else if(!want_recv)
   976→    return want_send && Curl_creader_is_paused(data);
   977→  else
   978→    return Curl_creader_is_paused(data) && Curl_cwriter_is_paused(data);
   979→}
