   241→
   242→  if(domain) {
   243→    len = strlen(domain);
   244→    last = memrchr(domain, '.', len);
   245→    if(last) {
   246→      first = memrchr(domain, '.', (last - domain));
   247→      if(first)
   248→        len -= (++first - domain);
   249→    }
   250→  }
   251→
   252→  if(outlen)
   253→    *outlen = len;
   254→
   255→  return first ? first : domain;
   256→}
